package com.google.gson.stream;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import java.io.StringWriter;

class JsonWriter_isLenient_Test {

  private JsonWriter jsonWriter;

  @BeforeEach
  void setUp() {
    jsonWriter = new JsonWriter(new StringWriter());
  }

  @Test
  void isLenient_DefaultIsFalse() {
    assertFalse(jsonWriter.isLenient());
  }

  @Test
  void isLenient_AfterSetLenientTrue_IsTrue() {
    jsonWriter.setLenient(true);
    assertTrue(jsonWriter.isLenient());
  }

  @Test
  void isLenient_AfterSetLenientFalse_IsFalse() {
    jsonWriter.setLenient(true);
    jsonWriter.setLenient(false);
    assertFalse(jsonWriter.isLenient());
  }
}
